You can use the `HttpClient` class in ASP.NET Core to make proxy requests to another endpoint. Here's an example of how you can do this:

```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet("{url}")]
    public async Task<IActionResult> GetAsync([FromRoute] string url)
    {
        var httpClient = _httpClientFactory.CreateClient();
        var response = await httpClient.GetAsync(url);

        if (response.IsSuccessStatusCode)
        {
            return new OkObjectResult(await response.Content.ReadAsStringAsync());
        }
        else
        {
            return new StatusCodeResult((int)response.StatusCode);
        }
    }
}
```

